sql:
SELECT COUNT(is_correct) AS total_correct_answers
FROM user_answers
WHERE is_correct = 1;

SELECT AVG(q.difficulty_level) AS average_difficulty_level
FROM questions q
WHERE q.related_word_id = 1;

